	.TITLE	TDGENC	.PROC	M680002	.REF	DRIVERS	.REF	LIB	.REF	SM8	.REF	DGENC	.LOC	0OBUGC:	.BLKB	MAXGC*LGGCOLIGC:	.BLKB	3*100LGVAR:	.LOC	0START:	LOAD.L	A6,#R16"VAR	LOAD.L	A4,A6	LOAD.W	D4,#LGVAR10$:	CLR.B	(A4+)	DEC.W	D4	JUMP,NE 10$	LOAD.W	D3,#2	.W	LIB,?MOUSE	LOAD.L	A3,#R16"NAME	LOAD.W	D3,#DGENC_FIRST	.W	LIB_OPEN	CLR.W	D2	CLR.L	D4	LOAD.L	A3,#(A6)+OBUGC	LOAD.L	A4,#(A6)+OLIGC	LOAD.W	D5,#3*100	.W	DGENC_MODIF	EXITNAME:	.ASCIZ	"DGENC"	.EVENVAR:	.BLKB	LGVAR	.END	START